"""
Pytest tests for weekly timesheet submission requirements:
- Each day must have hours between 0 and 24 (inclusive)
- Total weekly hours must be between 0 and 80 (inclusive)
- Submission must be idempotent under retry
"""

import pytest
from unittest.mock import MagicMock, patch, call
from dataclasses import dataclass, field
from typing import Dict, Optional
import uuid


# ---------------------------------------------------------------------------
# Domain model & service (inline so tests are self-contained)
# ---------------------------------------------------------------------------

class TimesheetValidationError(ValueError):
    """Raised when timesheet data fails validation."""


class TimesheetSubmissionError(RuntimeError):
    """Raised when the submission backend encounters an error."""


DAYS_OF_WEEK = ["monday", "tuesday", "wednesday", "thursday", "friday", "saturday", "sunday"]
MAX_DAILY_HOURS = 24
MAX_WEEKLY_HOURS = 80
MIN_HOURS = 0


@dataclass
class DailyEntry:
    day: str
    hours: float


@dataclass
class Timesheet:
    employee_id: str
    week_start_date: str          # ISO format, e.g. "2024-01-01"
    entries: Dict[str, float]     # {day_name: hours}
    idempotency_key: str = field(default_factory=lambda: str(uuid.uuid4()))

    @property
    def total_hours(self) -> float:
        return sum(self.entries.values())


def validate_timesheet(timesheet: Timesheet) -> None:
    """Validate a Timesheet object; raise TimesheetValidationError on failure."""
    for day, hours in timesheet.entries.items():
        if hours < MIN_HOURS or hours > MAX_DAILY_HOURS:
            raise TimesheetValidationError(
                f"Hours for {day} must be between {MIN_HOURS} and {MAX_DAILY_HOURS}, got {hours}"
            )

    total = timesheet.total_hours
    if total < MIN_HOURS or total > MAX_WEEKLY_HOURS:
        raise TimesheetValidationError(
            f"Total weekly hours must be between {MIN_HOURS} and {MAX_WEEKLY_HOURS}, got {total}"
        )


class TimesheetRepository:
    """Thin persistence abstraction (to be mocked in tests)."""

    def find_by_idempotency_key(self, key: str) -> Optional[Dict]:
        raise NotImplementedError

    def save(self, timesheet: Timesheet) -> Dict:
        raise NotImplementedError


class TimesheetService:
    """Application service that orchestrates validation and persistence."""

    def __init__(self, repository: TimesheetRepository):
        self._repo = repository

    def submit(self, timesheet: Timesheet) -> Dict:
        """
        Validate and persist a timesheet.

        Idempotent: if a submission with the same idempotency_key already
        exists, returns the stored result without re-persisting.
        """
        # Idempotency check BEFORE validation so retries are always safe
        existing = self._repo.find_by_idempotency_key(timesheet.idempotency_key)
        if existing is not None:
            return existing

        validate_timesheet(timesheet)
        return self._repo.save(timesheet)


