class TestDailyHoursValidation:

    def test_valid_daily_hours_passes(self):
        ts = make_timesheet(VALID_ENTRIES)
        validate_timesheet(ts)  # should not raise

    @pytest.mark.parametrize("hours", [0.0, 0.5, 8.0, 12.0, 23.5, 24.0])
    def test_boundary_daily_hours_are_valid(self, hours):
        entries = {**VALID_ENTRIES, "monday": hours}
        # Recalculate; ensure total stays <= 80
        entries["tuesday"] = min(8.0, MAX_WEEKLY_HOURS - sum(
            v for k, v in entries.items() if k != "tuesday"))
        ts = make_timesheet(entries)
        validate_timesheet(ts)  # should not raise

