class TestWeeklyTotalHoursValidation:

    def test_valid_total_hours_passes(self):
        entries = {**VALID_ENTRIES}  # 40 hrs
        ts = make_timesheet(entries)
        validate_timesheet(ts)

    @pytest.mark.parametrize("total", [0, 1, 40, 79, 80])
    def test_boundary_totals_are_valid(self, total):
        hours_per_day = total / 7
        # Use equal split; cap at 24 per day
        entries = {d: min(hours_per_day, 24.0) for d in DAYS_OF_WEEK}
        # Adjust last day for rounding
        diff = total - sum(entries.values())
        entries["sunday"] = round(entries["sunday"] + diff, 4)
        ts = make_timesheet(entries)
        validate_timesheet(ts)

    def test_total_hours_exceeding_80_raises(self):
        # 7 days × 12 = 84 hours
        entries = {d: 12.0 for d in DAYS_OF_WEEK}
        ts = make_timesheet(entries)
        with pytest.raises(TimesheetValidationError, match="80"):
            validate_timesheet(ts)

    def test_total_exactly_80_hours_is_valid(self):
        # e.g. five 16-hour days
        entries = {d: 0.0 for d in DAYS_OF_WEEK}
        entries["monday"] = 16.0
        entries["tuesday"] = 16.0
        entries["wednesday"] = 16.0
        entries["thursday"] = 16.0
        entries["friday"] = 16.0
        ts = make_timesheet(entries)
        validate_timesheet(ts)

    def test_total_of_81_hours_raises(self):
        entries = {d: 0.0 for d in DAYS_OF_WEEK}
        for day in ["monday", "tuesday", "wednesday", "thursday"]:
            entries[day] = 20.0
        entries["friday"] = 1.0   # total = 81
        ts = make_timesheet(entries)
        with pytest.raises(TimesheetValidationError, match="81"):
            validate_timesheet(ts)

    def test_total_hours_property_calculated_correctly(self):
        ts = make_timesheet(VALID_ENTRIES)
        assert ts.total_hours == pytest.approx(40.0)


