        mock_repo.save.assert_called_once_with(ts)

    def test_submit_checks_idempotency_key_before_save(self, service, mock_repo):
        ts = make_timesheet(VALID_ENTRIES)
        mock_repo.save.return_value = {"id": "ts-001"}

        service.submit(ts)

        mock_repo.find_by_idempotency_key.assert_called_once_with(ts.idempotency_key)

    def test_submit_invalid_timesheet_raises_validation_error(self, service, mock_repo):
