# ===========================================================================
# 4. Idempotency under retry
# ===========================================================================

class TestIdempotency:

    def test_second_submission_same_key_returns_original_result(self, service, mock_repo):
        ts = make_timesheet(VALID_ENTRIES, key="idem-key-1")
        stored_result = {"id": "ts-999", "status": "submitted"}

        # First call: not found → save
        mock_repo.find_by_idempotency_key.return_value = None
        mock_repo.save.return_value = stored_result
        first_result = service.submit(ts)

        # Simulate stored record now exists
        mock_repo.find_by_idempotency_key.return_value = stored_result
        second_result = service.submit(ts)

        assert first_result == second_result == stored_result

    def test_retry_does_not_call_save_again(self, service, mock_repo):
        ts = make_timesheet(VALID_ENTRIES, key="idem-key-2")
        stored_result = {"id": "ts-888", "status": "submitted"}
        mock_repo.find_by_idempotency_key.return_value = stored_result

        service.submit(ts)
        service.submit(ts)
        service.submit(ts)

        mock_repo.save.assert_not_called()

    def test_multiple_retries_always_return_same_result(self, service, mock_repo):
        ts = make_timesheet(VALID_ENTRIES, key="idem-key-3")
        stored_result = {"id": "ts-777", "status": "submitted"}
        mock_repo.find_by_idempotency_key.return_value = stored_result

        results = [service.submit(ts) for _ in range(10)]

        assert all(r == stored_result for r in results)

    def test_different_idempotency_keys_are_independent_submissions(
        self, service, mock_repo
    ):
        ts1 = make_timesheet(VALID_ENTRIES, key="key-A")
        ts2 = make_timesheet(VALID_ENTRIES, key="key-B")
        result_a = {"id": "ts-A"}
        result_b = {"id": "ts-B"}

        mock_repo.find_by_idempotency_key.return_value = None
        mock_repo.save.side_effect = [result_a, result_b]

        r1 = service.submit(ts1)
        r2 = service.submit(ts2)

        assert r1 == result_a
        assert r2 == result_b
        assert mock_repo.save.call_count == 2

    def test_idempotency_check_occurs_before_validation(self, service, mock_repo):
        """
        A retry with an already-stored key must succeed even if the caller
        passes a (now-invalid) payload, because the original was valid.
        """
        bad_entries = {**VALID_ENTRIES, "monday": 99.0}  # invalid
        ts = make_timesheet(bad_entries, key="idem-key-retry")
        stored_result = {"id": "ts-original", "status": "submitted"}

        # Simulate the original valid submission already stored
        mock_repo.find_by_idempotency_key.return_value = stored_result

        # Should NOT raise despite invalid entries because key already exists
        result = service.submit(ts)
        assert result == stored_result
        mock_repo.save.assert_not_called()

    def test_idempotency_key_is_passed_correctly_to_repository(self, service, mock_repo):
        key = "specific-idempotency-key-xyz"
        ts = make_timesheet(VALID_ENTRIES, key=key)
        mock_repo.save.return_value = {"id": "ts-001"}

        service.submit(ts)

        mock_repo.find_by_idempotency_key.assert_called_with(key)

    def test_concurrent_retries_only_persist_once(self, mock_repo):
        """
        Simulate a race-condition scenario: two calls arrive before either
        has persisted; the repository itself is the authority — only one
        save should be attempted per unique key in a correctly implemented
        service.  Here we verify the service calls save exactly once when
        find_by_idempotency_key consistently returns None (single-threaded
        sequential simulation).
        """
        ts = make_timesheet(VALID_ENTRIES, key="race-key")
        mock_repo.find_by_idempotency_key.return_value = None
        mock_repo.save.return_value = {"id": "ts-race"}

        # Sequential calls that both "miss" the cache (repo not yet updated)
        service_instance = TimesheetService(mock_repo)
        service_instance.submit(ts)

        # After first save, repo now returns result
        mock_repo.find_by_idempotency_key.return_value = {"id": "ts-race"}
        service_instance.submit(ts)

        mock_repo.save.assert_called_once()


# ===========================================================================
# 5. Edge cases & combined rules
# ===========================================================================

class TestEdgeCases:

    def test_single_day_timesheet_with_valid_hours(self):
        entries = {"monday": 8.0}
        ts = make_timesheet(entries)
        validate_timesheet(ts)

    def test_fractional_hours_are_accepted(self):
        entries = {**VALID_ENTRIES, "monday": 7.5, "tuesday": 8.5}
        ts = make_timesheet(entries)
        validate_timesheet(ts)  # 7.5+8.5+8+8+8+0+0 = 40, valid

    def test_sum_just_over_80_raises(self):
        entries = {d: 0.0 for d in DAYS_OF_WEEK}
        entries["monday"] = 24.0
        entries["tuesday"] = 24.0
        entries["wednesday"] = 24.0
        entries["thursday"] = 8.01   # total = 80.01
        ts = make_timesheet(entries)
        with pytest.raises(TimesheetValidationError):
            validate_timesheet(ts)

    def test_all_days_at_maximum_24_raises_weekly_limit(self):
        entries = {d: 24.0 for d in DAYS_OF_WEEK}  # total = 168
        ts = make_timesheet(entries)
        with pytest.raises(TimesheetValidationError, match="168"):
            validate_timesheet(ts)

    def test_empty_entries_is_valid_zero_total(self):
        ts = make_timesheet({})
        validate_timesheet(ts)  # 0 total hours is valid

    def test_timesheet_total_hours_property_with_empty_entries(self):
        ts = make_timesheet({})
        assert ts.total_hours == 0.0

    @pytest.mark.parametrize("invalid_hours,day", [
        (-0.001, "monday"),
        (24.001, "tuesday"),
        (float("inf"), "wednesday"),
    ])
    def test_out_of_range_daily_hours_raise(self, invalid_hours, day):
        entries = {**VALID_ENTRIES, day: invalid_hours}
        ts = make_timesheet(entries)
        with pytest.raises(TimesheetValidationError):
            validate_timesheet(ts)

    def test_unique_idempotency_keys_generated_by_default(self):
        ts1 = Timesheet(employee_id="e1", week_start_date="2024-01-01", entries={})
        ts2 = Timesheet(employee_id="e1", week_start_date="2024-01-01", entries={})
        assert ts1.idempotency_key != ts2.idempotency_key
